```json
{
  "global": "Navigate to the music platform, locate the 'Most Popular of All Time' tab within the charts or browse section, and add it to a user playlist.",
  "subtasks": [
    {
      "subtask": "Open the music platform and reach the charts or browse section",
      "atomics": [
        "Click on the music application entry point or navigate to the music URL",
        "Locate and click the 'Charts', 'Browse', or 'Discover' navigation item",
        "Confirm the charts/browse page has loaded by verifying visible tab labels"
      ]
    },
    {
      "subtask": "Identify and select the 'Most Popular of All Time' tab",
      "atomics": [
        "Scan visible tabs or filter options for a label matching 'Most Popular of All Time' or equivalent",
        "Click the 'Most Popular of All Time' tab to make it the active view",
        "Verify the tab content (track list or chart) is displayed under the selected tab"
      ]
    },
    {
      "subtask": "Trigger the add-to-playlist action on the active tab",
      "atomics": [
        "Locate the overflow menu, context menu, or 'Add to Playlist' button associated with the tab or its content",
        "Click the 'Add to Playlist' or equivalent action item",
        "Select the target playlist from the presented list or dropdown"
      ]
    },
    {
      "subtask": "Confirm the tab or its contents have been added to the playlist",
      "atomics": [
        "Check for a success toast, confirmation banner, or modal indicating the item was added",
        "Navigate to the target playlist and verify the 'Most Popular of All Time' tab or its tracks appear"
      ]
    }
  ],
  "global_atomics": [
    "If a login wall or authentication prompt appears at any point, enter credentials and retry the interrupted step",
    "If the exact label 'Most Popular of All Time' is not found, inspect all visible tab labels for the closest semantic match before proceeding"
  ],
  "gold_actions": {
    "global": "Execute a multi-step web navigation sequence: load the music platform, click into the charts browse view, activate the 'Most Popular of All Time' tab, invoke 'Add to Playlist', select a playlist, and verify the confirmation signal.",
    "subtasks": [
      {
        "subtask": "Load the music platform and navigate to the charts or browse section",
        "atomics": [
          "Click the application launcher icon or type the music platform URL into the browser address bar and press Enter",
          "Click the 'Charts' or 'Browse' link in the primary navigation sidebar or top menu bar",
          "Assert that the page heading or active nav item reads 'Charts' or 'Browse' to confirm correct page state"
        ]
      },
      {
        "subtask": "Activate the 'Most Popular of All Time' tab",
        "atomics": [
          "Scan the horizontal tab bar on the charts page and identify the element with text 'Most Popular of All Time'",
          "Click the 'Most Popular of All Time' tab element to set it as the active tab",
          "Assert that a track list or content block is rendered beneath the now-active tab"
        ]
      },
      {
        "subtask": "Invoke add-to-playlist on the active tab content",
        "atomics": [
          "Click the three-dot overflow icon, right-click for a context menu, or locate a dedicated 'Add to Playlist' button near the tab header or first list item",
          "Click the 'Add to Playlist' menu item in the context menu or action panel",
          "Click the desired playlist name in the playlist picker dropdown or modal to confirm the target"
        ]
      },
      {
        "subtask": "Verify successful addition to the playlist",
        "atomics": [
          "Read the success toast or confirmation banner text (e.g., 'Added to [Playlist Name]') to confirm the action completed",
          "Navigate to the target playlist view and assert that the added tab content or tracks appear in the playlist item list"
        ]
      }
    ],
    "global_atomics": [
      "If an authentication modal is detected (login form visible), fill in the username and password fields and click 'Sign In', then resume from the last incomplete step",
      "If no tab label exactly matches 'Most Popular of All Time', use fuzzy matching across all visible tab texts and select the highest-confidence match (e.g., 'All-Time Popular', 'Top of All Time') before continuing"
    ]
  }
}
```
